CREATE View         [dbo].[v6_007_unpostedbatches]             -- with encryption             as             select      periodends                                                          as PeriodEnds             ,           isnull(gldicj,'1901-01-01') 
          as BatchDate             ,           glco                as CompanyNumber             ,           glicut                as Type             ,           max(gluser)                                                         as Username             ,
           longaccount                                                         as LongAccount             ,           glicu                as BatchNumber             ,case when  iciapp is null      then 'Missing batch header'             when        iciap
p = 'p'        then 'Pending approval'             else        'Approved'          end                                             as Apprsts             ,case when  icist is null       then    'Missing Header'             when        icist = ' '         
then    'Pending'             when        icist = 'a'         then    'Approved'             when        icist = 'd'         then    'Posted'             when        icist = 'e'         then    'Error'             when        icist = 'p'         then    '
Posting'             when        icist = 'u'         then    'In use'             else        ''                  end                                             as Poststs             ,           sum(glaa)               as Amount     from  f0911     join
        rinvaccountlist b    on          glaid = b.shortaccount    and         glco = b.companynumber     join  rfiscalcalendar fc    on   glco = fc.companynumber    and   gldgj between periodbegins and periodends     left join   f0011    on          glic
u = icicu    and         glicut = icicut     where  glpost <> 'P'     group by periodends    ,   gldicj    ,   glco    ,   glicut    ,   longaccount    ,   glicu    ,   iciapp    ,   icist
